{"code":"import json
import re

# Load funding data
with open(locals()['var_function_call_14956260562366733902'], 'r') as f:
    funding_data = json.load(f)

# Filter funding data
funded_projects = {}
for item in funding_data:
    try:
        amount = float(item['Amount'])
        if amount > 50000:
            funded_projects[item['Project_Name'].strip()] = amount
    except ValueError:
        continue

# Load civic docs
with open(locals()['var_function_call_4179271317217180395'], 'r') as f:
    docs = json.load(f)

design_capital_projects = set()

for doc in docs:
    text = doc.get('text', '')
    lines = text.split('\n')

    in_design_section = False

    for line in lines:
        line = line.strip()
        if not line:
            continue

        # Markers for sections
        if "Capital Improvement Projects (Design)" in line:
            in_design_section = True
            continue

        # Stop if we hit other sections
        if "Capital Improvement Projects (Construction)" in line:
            in_design_section = False
            continue
        if "Capital Improvement Projects (Not Started)" in line:
            in_design_section = False
            continue
        if "Disaster Recovery Projects" in line:
            in_design_section = False
            continue

        if in_design_section:
            if "Updates:" in line or "Schedule:" in line or "Page " in line or "Agenda Item" in line:
                continue
            if line.startswith("("):
                continue
            if "Prepared by" in line or "Approved by" in line:
                continue

            # Additional cleanup
            if len(line) < 3:
                continue

            design_capital_projects.add(line)

# Match
count = 0
matches = []
funded_names = set(funded_projects.keys())

for proj in design_capital_projects:
    if proj in funded_names:
        count += 1
        matches.append(proj)

print("__RESULT__:")
print(json.dumps({"count": count, "matches": matches, "extracted": list(design_capital_projects)}))
"}

{"code":"import json

# Access variables
funding_file = locals()['var_function_call_14956260562366733902']
docs_file = locals()['var_function_call_4179271317217180395']

with open(funding_file, 'r') as f:
    funding = json.load(f)

with open(docs_file, 'r') as f:
    docs = json.load(f)

# Funding set > 50k
funded = set()
for x in funding:
    try:
        if float(x['Amount']) > 50000:
            funded.add(x['Project_Name'].strip())
    except:
        pass

# Extract
extracted = set()
for doc in docs:
    txt = doc.get('text', '')
    lines = txt.split('\n')
    active = False
    for line in lines:
        line = line.strip()
        if 'Capital Improvement Projects (Design)' in line:
            active = True
            continue
        if 'Capital Improvement Projects' in line and '(Design)' not in line:
            active = False
            continue
        if 'Disaster Recovery Projects' in line:
            active = False
            continue

        if active:
            # Filters
            if not line or line.startswith('(') or 'Updates:' in line or 'Schedule:' in line or 'Page' in line or 'Agenda' in line:
                continue
            if 'Prepared by' in line or 'Approved by' in line:
                continue
            if len(line) < 5:
                continue
            extracted.add(line)

# Intersection
matches = [p for p in extracted if p in funded]
print('__RESULT__:')
print(json.dumps({'count': len(matches), 'matches': matches, 'extracted': list(extracted)}))"}

